/**
 * Mock data for Growth · Content Gaps.
 *
 * Each row is demand with no page — measured from Search Console + catalog.
 * Per-row "flag" drives the colored left rail (blind / urgent / trap).
 * Detail panel shows the money + leak bar + competitor lock-out.
 */

export type GapFlag = "" | "blind" | "urgent" | "trap";

export interface GapRow {
  rank: number;
  name: string;
  flag: GapFlag;
  flagLabel: string;
  money: number;
  moneyStr: string;
  /** Optional daily bleed badge (only for urgent rows). */
  bleed?: string;
  demand: number;
  demandStr: string;
  /** 0–100 — buyer-intent % */
  intent: number;
  intentWord: string;
  /** Number of products already in your catalog matching the gap (null for content/trap). */
  ready: number | null;
  effort: string;
  /** Competitor lock-out sentence: "deskhaus · workwell · ergodepot hold #1–3" */
  comps: string;
  /** Kicker shown in the detail header. */
  kicker: string;
  moneySub: string;
  /** Italic argument line at the bottom of the detail. */
  line: string;
  /** Whether the row is actionable (false = a trap to skip). */
  actionable: boolean;
  /** Marks this as content-gap (no product list, content authority play). */
  content?: boolean;
  /** Marks as trap. */
  trap?: boolean;
}

