"use client";

import { useEffect, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  GAPS,
  MAX_GAP_MONEY,
  gapsMetrics,
  gapsAI,
  type GapRow,
} from "@/features/growth/api/growth-gaps-data";
import "./gaps.css";

export default function ContentGapsPage() {
  const [selected, setSelected] = useState<number | null>(null);
  const { openBridge } = useBridge();

  return (
    <div className="growth-gaps-page">
      <DeptHeader
        dept="growth"
        title="Content Gaps"
        meta={
          <>
            <span className="live">Live</span> · Demand with no page · from Search Console + catalog
          </>
        }
        actions={
          <>
            <button className="btn-util">Export scan</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("growth")}
            >
              Build top gap →
            </button>
          </>
        }
      />
      <div className="head-pad" />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Money on the table</div>
          <div className="metric-v green">{gapsMetrics.money}</div>
          <div className="metric-s">{gapsMetrics.moneySub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Unmet demand</div>
          <div className="metric-v">{gapsMetrics.demand}</div>
          <div className="metric-s">{gapsMetrics.demandSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Gaps found</div>
          <div className="metric-v">{gapsMetrics.found}</div>
          <div className="metric-s">{gapsMetrics.foundSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Catalog-ready</div>
          <div className="metric-v green">{gapsMetrics.catalogReady}</div>
          <div className="metric-s">{gapsMetrics.catalogReadySub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Seasonal urgent</div>
          <div className="metric-v amber">{gapsMetrics.urgent}</div>
          <div className="metric-s">{gapsMetrics.urgentSub}</div>
        </div>
      </div>

      <AIStrip label={gapsAI.label} meta={gapsAI.meta} cards={gapsAI.cards} />

      <SectionLabel>Every gap, ranked by what it&rsquo;s worth — select to see the leak</SectionLabel>
      <div className={`gaps-split${selected !== null ? " open" : ""}`}>
        <div className="gaps-main">
          <div className="gaps-list">
            {GAPS.map((g, i) => (
              <GapRowEl
                key={g.rank}
                gap={g}
                selected={selected === i}
                onSelect={() => setSelected((cur) => (cur === i ? null : i))}
              />
            ))}
          </div>
        </div>
        <aside className="gaps-detail">
          {selected !== null && (
            <GapDetail
              gap={GAPS[selected]}
              onClose={() => setSelected(null)}
              openBridge={() => openBridge("growth")}
            />
          )}
        </aside>
      </div>
    </div>
  );
}

interface RowProps {
  gap: GapRow;
  selected: boolean;
  onSelect: () => void;
}

function GapRowEl({ gap, selected, onSelect }: RowProps) {
  const w = Math.max(2, Math.round((gap.money / MAX_GAP_MONEY) * 100));
  const flagCls = gap.flag ? `flag-${gap.flag}` : "";
  return (
    <div
      className={`g-row ${flagCls}${selected ? " sel" : ""}`}
      onClick={onSelect}
    >
      <div className="g-rank">{gap.rank}</div>
      <div className="g-main">
        <div className="g-name">
          {gap.name}
          {gap.flagLabel && <span className={`fw ${gap.flag}`}>{gap.flagLabel}</span>}
        </div>
        <div className="g-bar-row">
          <div className="g-bar">
            <div className={`g-bar-fill${gap.trap ? " muted" : ""}`} style={{ width: `${w}%` }} />
          </div>
          <div className="g-ready">
            {gap.content || gap.ready === null ? (
              <span className="zero">needs new page</span>
            ) : (
              <>
                <b>{gap.ready} ready</b> · <span className="zero">0 pages</span>
              </>
            )}
          </div>
        </div>
      </div>
      <div className="g-money">
        <div className={`m${gap.trap ? " muted" : ""}`}>{gap.moneyStr}</div>
        <div className="u">/mo at stake</div>
        {gap.bleed && <div className="bleed">{gap.bleed}</div>}
      </div>
    </div>
  );
}

interface DetailProps {
  gap: GapRow;
  onClose: () => void;
  openBridge: () => void;
}

function GapDetail({ gap, onClose, openBridge }: DetailProps) {
  const fillW = Math.max(4, gap.intent);
  // The leak bar animates from 0 → fillW on mount.
  const [animatedW, setAnimatedW] = useState(0);
  useEffect(() => {
    setAnimatedW(0);
    const r1 = requestAnimationFrame(() =>
      requestAnimationFrame(() => setAnimatedW(fillW)),
    );
    return () => cancelAnimationFrame(r1);
  }, [fillW, gap.name]);

  const ready = gap.content || gap.ready === null ? "—" : String(gap.ready);
  const readyL = gap.content || gap.ready === null ? "catalog match" : "products ready";
  const trapMute = gap.trap ? " muted" : "";

  // Shut-out fact varies by gap type
  let shutFact: string;
  if (gap.trap) {
    shutFact = "The top spots aren't winnable — and wouldn't pay if they were.";
  } else if (gap.content) {
    shutFact = "Three editorial pages own this topic.";
  } else {
    shutFact = "You're shut out of the top three.";
  }
  const shutMe = gap.trap ? "You: don't bother." : "You: not ranking.";

  return (
    <div className="gap-detail">
      <button className="gd-clear" aria-label="Close" onClick={onClose} type="button">✕</button>
      <div className={`gd-kicker ${gap.flag || ""}`}>
        <span className="kdot" />
        {gap.kicker}
      </div>
      <div className="gd-name">{gap.name}</div>
      <div className="gd-money">
        <span className={`big${trapMute}`}>{gap.moneyStr}</span>
        <span className="per">/mo</span>
      </div>
      <div className="gd-money-sub">
        {gap.moneySub}
        {gap.bleed && <span className="bld">{gap.bleed} while open</span>}
      </div>

      <div className="leak">
        <div className="leak-cap">
          <span>Buyer-intent demand</span>
          <span className="v">
            {gap.intent}% of {gap.demandStr}/mo
          </span>
        </div>
        <div className="leak-track">
          <div
            className={`leak-fill${trapMute}`}
            style={{ width: `${animatedW}%` }}
          />
        </div>
        <div className="you-track">
          <span className="yl">Your capture</span>
          <span className="yv">0 — no page</span>
        </div>
      </div>

      <div className="gd-stats">
        <div className="gd-stat">
          <div className={`v${gap.content || gap.ready === null ? "" : " green"}`}>{ready}</div>
          <div className="l">{readyL}</div>
        </div>
        <div className="gd-stat">
          <div className="v red">0</div>
          <div className="l">pages targeting it</div>
        </div>
        <div className="gd-stat">
          <div className="v">{gap.demandStr}</div>
          <div className="l">monthly searches</div>
        </div>
      </div>

      <div className="gd-shut">
        <div className="fact">{shutFact}</div>
        <div className="who">
          {gap.comps}. <span className="me">{shutMe}</span>
        </div>
      </div>

      <div className="gd-actions">
        {gap.trap ? (
          <>
            <span className="eff">{gap.effort}</span>
            <button className="btn-util" type="button">Mark reviewed</button>
          </>
        ) : (
          <>
            <span className="eff">Effort: {gap.effort}</span>
            <button className="btn-util" type="button">Dismiss</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={openBridge}
            >
              Build in Bridge →
            </button>
          </>
        )}
      </div>
    </div>
  );
}
