/* ════════════════════════════════════════════════════════════════════════
   SectionLabel — mono-uppercase label + dashed rule + optional right slot.
   Canonical per style guide §0.6.

   Usage:
     <SectionLabel>Where is your money going?</SectionLabel>

     <SectionLabel
       sub="next 14 days"
       right={<a href="/receiving">Open in Receiving →</a>}
     >
       Inbound landings
     </SectionLabel>
   ════════════════════════════════════════════════════════════════════════ */

import type React from "react";

export interface SectionLabelProps {
  children: React.ReactNode;
  /** Smaller secondary text shown next to the label */
  sub?: React.ReactNode;
  /** Right-side link/action (rendered before the dashed rule on smaller widths) */
  right?: React.ReactNode;
}

export function SectionLabel({ children, sub, right }: SectionLabelProps) {
  return (
    <div className="section-label-row">
      <span>
        {children}
        {sub && <span className="section-label-sub">{sub}</span>}
      </span>
      {right && <span className="section-label-right">{right}</span>}
    </div>
  );
}
